import React, { useState, useEffect, useCallback } from 'react';
import { useWeb3 } from '../contexts/Web3Context';
import { useSettings } from '../contexts/SettingsContext';
import { ethers } from 'ethers';
import { 
  Clock, 
  CheckCircle, 
  XCircle, 
  Filter,
  RefreshCw,
  User,
  Users
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import toast from 'react-hot-toast';

const ClaimsList = () => {
  const { account, provider, signer, network, isConnected } = useWeb3();
  const { getBridgeInstancesWithSettings } = useSettings();

  const [claims, setClaims] = useState([]);
  const [loading, setLoading] = useState(false);
  const [refreshing, setRefreshing] = useState(false);
  const [filter, setFilter] = useState('all'); // 'all' or 'my'
  const [currentBlock, setCurrentBlock] = useState(null);

  // Load claims from all bridge instances on the current network
  const loadClaims = useCallback(async () => {
    if (!account || !provider || !network) return;

    setLoading(true);
    try {
      const bridgeInstances = getBridgeInstancesWithSettings();
      const currentNetworkName = network.name;

      // Find all bridge instances for the current network
      const networkBridges = Object.values(bridgeInstances).filter(bridge => 
        bridge.homeNetwork === currentNetworkName || bridge.foreignNetwork === currentNetworkName
      );

      if (networkBridges.length === 0) {
        console.log('No bridge instances found for current network:', currentNetworkName);
        setClaims([]);
        return;
      }

      // Get current block and timestamp
      const block = await provider.getBlock('latest');
      setCurrentBlock(block);
      const currentTimestamp = block.timestamp;

      // Load Counterstake ABI
      const counterstakeAbi = [
        "function last_claim_num() view returns (uint64)",
        "function getOngoingClaimNums() view returns (uint64[])",
        "function getClaim(uint256) view returns (tuple(uint256 amount, address recipient_address, uint32 txts, uint32 ts, address claimant_address, uint32 expiry_ts, uint16 period_number, uint8 current_outcome, bool is_large, bool withdrawn, bool finished, string sender_address, string data, uint256 yes_stake, uint256 no_stake))",
        "function stakes(uint256, uint8, address) view returns (uint256)"
      ];

      const allClaims = [];

      // Fetch claims from each bridge instance
      for (const bridge of networkBridges) {
        try {
          console.log(`Fetching claims from bridge: ${bridge.address} (${bridge.type})`);

          const contract = new ethers.Contract(bridge.address, counterstakeAbi, provider);

          // Get last claim number
          const lastClaimNum = await contract.last_claim_num();
          console.log(`Last claim number for ${bridge.address}: ${lastClaimNum.toString()}`);

          // Get ongoing claim numbers
          const ongoingClaimNums = await contract.getOngoingClaimNums();
          console.log(`Ongoing claim numbers: ${ongoingClaimNums.map(n => n.toString()).join(', ')}`);

          // Fetch last 100 claims (or all if less than 100)
          const startClaimNum = Math.max(1, lastClaimNum.toNumber() - 99);
          const endClaimNum = lastClaimNum.toNumber();

          for (let claimNum = startClaimNum; claimNum <= endClaimNum; claimNum++) {
            try {
              // Check if claim exists by checking stakes
              const testAccount = "0x3bC6F415BbE667E0Fdaca81b7A78E8AE6469E688";
              const accountYesStake = await contract.stakes(claimNum, 0, testAccount); // 0 = YES
              const accountNoStake = await contract.stakes(claimNum, 1, testAccount);   // 1 = NO

              if (accountYesStake.gt(0) || accountNoStake.gt(0)) {
                // Claim exists, get detailed information
                const claimData = await contract.getClaim(claimNum);

                const claim = {
                  claimNum,
                  bridgeAddress: bridge.address,
                  bridgeType: bridge.type,
                  bridgeName: `${bridge.homeNetwork} → ${bridge.foreignNetwork}`,
                  amount: ethers.utils.formatEther(claimData.amount),
                  recipientAddress: claimData.recipient_address,
                  senderAddress: claimData.sender_address,
                  claimantAddress: claimData.claimant_address,
                  txts: claimData.txts,
                  ts: claimData.ts,
                  expiryTs: claimData.expiry_ts,
                  periodNumber: claimData.period_number,
                  currentOutcome: claimData.current_outcome === 0 ? 'NO' : 'YES',
                  isLarge: claimData.is_large,
                  withdrawn: claimData.withdrawn,
                  finished: claimData.finished,
                  data: claimData.data,
                  yesStake: ethers.utils.formatEther(claimData.yes_stake),
                  noStake: ethers.utils.formatEther(claimData.no_stake),
                  timeRemaining: claimData.expiry_ts - currentTimestamp,
                  isExpired: claimData.expiry_ts < currentTimestamp,
                  isMyClaim: claimData.recipient_address.toLowerCase() === account.toLowerCase()
                };

                allClaims.push(claim);
              }
            } catch (error) {
              // Skip claims that don't exist or have errors
              if (!error.message.includes('no such claim') && !error.message.includes('claim does not exist')) {
                console.error(`Error fetching claim ${claimNum}:`, error);
              }
            }
          }
        } catch (error) {
          console.error(`Error fetching claims from bridge ${bridge.address}:`, error);
        }
      }

      // Sort claims by claim number (newest first)
      allClaims.sort((a, b) => b.claimNum - a.claimNum);

      setClaims(allClaims);
      console.log(`Loaded ${allClaims.length} claims`);

    } catch (error) {
      console.error('Error loading claims:', error);
      toast.error(`Failed to load claims: ${error.message}`);
    } finally {
      setLoading(false);
    }
  }, [account, provider, network, getBridgeInstancesWithSettings]);

  // Refresh claims
  const refreshClaims = async () => {
    setRefreshing(true);
    await loadClaims();
    setRefreshing(false);
  };

  // Load claims on mount and when dependencies change
  useEffect(() => {
    if (isConnected) {
      loadClaims();
    }
  }, [loadClaims, isConnected]);

  // Auto-refresh every 30 seconds
  useEffect(() => {
    if (!isConnected) return;

    const interval = setInterval(() => {
      loadClaims();
    }, 30000);

    return () => clearInterval(interval);
  }, [loadClaims, isConnected]);

  // Filter claims based on current filter
  const filteredClaims = claims.filter(claim => {
    if (filter === 'my') {
      return claim.isMyClaim;
    }
    return true; // 'all' filter
  });

  if (!isConnected) {
    return (
      <div className="text-center py-12">
        <div className="text-secondary-400 mb-4">
          <Clock className="w-12 h-12 mx-auto mb-4" />
          <h3 className="text-lg font-semibold text-white mb-2">Connect Wallet</h3>
          <p className="text-secondary-400">
            Connect your wallet to view claims
          </p>
        </div>
      </div>
    );
  }

  const getStatusIcon = (claim) => {
    if (claim.finished) {
      return <CheckCircle className="w-5 h-5 text-success-500" />;
    }
    if (claim.isExpired) {
      return <XCircle className="w-5 h-5 text-error-500" />;
    }
    return <Clock className="w-5 h-5 text-warning-500" />;
  };

  const getStatusText = (claim) => {
    if (claim.finished) {
      return 'Finished';
    }
    if (claim.isExpired) {
      return 'Expired';
    }
    return 'Active';
  };

  const getStatusColor = (claim) => {
    if (claim.finished) {
      return 'text-success-500';
    }
    if (claim.isExpired) {
      return 'text-error-500';
    }
    return 'text-warning-500';
  };

  const formatAddress = (address) => {
    if (!address) return 'N/A';
    return `${address.slice(0, 6)}...${address.slice(-4)}`;
  };

  const formatAmount = (amount) => {
    return parseFloat(amount).toFixed(6);
  };

  const formatDate = (timestamp) => {
    if (!timestamp) return 'N/A';
    return new Date(timestamp * 1000).toLocaleString();
  };

  const formatTimeRemaining = (seconds) => {
    if (seconds <= 0) return 'Expired';
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    if (hours > 0) {
      return `${hours}h ${minutes}m remaining`;
    }
    return `${minutes}m remaining`;
  };

  return (
    <div className="max-w-6xl mx-auto">
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <div>
          <h2 className="text-2xl font-bold text-white mb-2">Claims</h2>
          <p className="text-secondary-400">
            View all claims on {network.name}
          </p>
        </div>
        <div className="flex items-center gap-4">
          {/* Filter Toggle */}
          <div className="flex bg-dark-800 rounded-lg p-1">
            <button
              onClick={() => setFilter('all')}
              className={`flex items-center gap-2 px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                filter === 'all'
                  ? 'bg-primary-600 text-white'
                  : 'text-secondary-400 hover:text-white hover:bg-dark-700'
              }`}
            >
              <Users className="w-4 h-4" />
              All Claims
            </button>
            <button
              onClick={() => setFilter('my')}
              className={`flex items-center gap-2 px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                filter === 'my'
                  ? 'bg-primary-600 text-white'
                  : 'text-secondary-400 hover:text-white hover:bg-dark-700'
              }`}
            >
              <User className="w-4 h-4" />
              My Claims
            </button>
          </div>

          {/* Refresh Button */}
          <button
            onClick={refreshClaims}
            disabled={refreshing}
            className="btn-secondary flex items-center gap-2"
          >
            <RefreshCw className={`w-4 h-4 ${refreshing ? 'animate-spin' : ''}`} />
            Refresh
          </button>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
        <div className="card">
          <div className="text-2xl font-bold text-white">{claims.length}</div>
          <div className="text-secondary-400 text-sm">Total Claims</div>
        </div>
        <div className="card">
          <div className="text-2xl font-bold text-white">{claims.filter(c => c.isMyClaim).length}</div>
          <div className="text-secondary-400 text-sm">My Claims</div>
        </div>
        <div className="card">
          <div className="text-2xl font-bold text-white">{claims.filter(c => !c.finished && !c.isExpired).length}</div>
          <div className="text-secondary-400 text-sm">Active Claims</div>
        </div>
        <div className="card">
          <div className="text-2xl font-bold text-white">{claims.filter(c => c.finished).length}</div>
          <div className="text-secondary-400 text-sm">Finished Claims</div>
        </div>
      </div>

      {/* Loading State */}
      {loading && (
        <div className="text-center py-12">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary-500 mx-auto mb-4"></div>
          <p className="text-secondary-400">Loading claims...</p>
        </div>
      )}

      {/* Empty State */}
      {!loading && filteredClaims.length === 0 && (
        <div className="text-center py-12">
          <div className="text-secondary-400 mb-4">
            <Clock className="w-12 h-12 mx-auto mb-4" />
            <h3 className="text-lg font-semibold text-white mb-2">No Claims Found</h3>
            <p className="text-secondary-400">
              {filter === 'my' 
                ? 'You don\'t have any claims on this network' 
                : 'No claims found on this network'
              }
            </p>
          </div>
        </div>
      )}

      {/* Claims List */}
      <AnimatePresence>
        {filteredClaims.map((claim, index) => (
          <motion.div
            key={`${claim.bridgeAddress}-${claim.claimNum}`}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            transition={{ delay: index * 0.05 }}
            className="card mb-4"
          >
            <div className="flex items-start justify-between">
              {/* Claim Info */}
              <div className="flex-1">
                <div className="flex items-center gap-3 mb-3">
                  {getStatusIcon(claim)}
                  <span className={`text-sm font-medium ${getStatusColor(claim)}`}>
                    {getStatusText(claim)}
                  </span>
                  <span className="text-sm text-secondary-400">
                    Claim #{claim.claimNum}
                  </span>
                  {claim.isMyClaim && (
                    <span className="bg-primary-900/50 text-primary-400 text-xs px-2 py-1 rounded border border-primary-700">
                      My Claim
                    </span>
                  )}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 text-sm mb-3">
                  <div>
                    <span className="text-secondary-400">Amount:</span>
                    <span className="text-white ml-2 font-medium">
                      {formatAmount(claim.amount)} {network.symbol}
                    </span>
                  </div>

                  <div>
                    <span className="text-secondary-400">Bridge:</span>
                    <span className="text-white ml-2 font-medium">
                      {claim.bridgeName}
                    </span>
                  </div>

                  <div>
                    <span className="text-secondary-400">Outcome:</span>
                    <span className={`ml-2 font-medium ${
                      claim.currentOutcome === 'YES' ? 'text-success-500' : 'text-error-500'
                    }`}>
                      {claim.currentOutcome}
                    </span>
                  </div>

                  <div>
                    <span className="text-secondary-400">Created:</span>
                    <span className="text-white ml-2">
                      {formatDate(claim.ts)}
                    </span>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 text-sm mb-3">
                  <div>
                    <span className="text-secondary-400">Recipient:</span>
                    <span className="text-white ml-2 font-mono">
                      {formatAddress(claim.recipientAddress)}
                    </span>
                  </div>

                  <div>
                    <span className="text-secondary-400">Claimant:</span>
                    <span className="text-white ml-2 font-mono">
                      {formatAddress(claim.claimantAddress)}
                    </span>
                  </div>

                  <div>
                    <span className="text-secondary-400">YES Stake:</span>
                    <span className="text-white ml-2 font-medium">
                      {formatAmount(claim.yesStake)} {network.symbol}
                    </span>
                  </div>

                  <div>
                    <span className="text-secondary-400">NO Stake:</span>
                    <span className="text-white ml-2 font-medium">
                      {formatAmount(claim.noStake)} {network.symbol}
                    </span>
                  </div>
                </div>

                {!claim.finished && (
                  <div className="mt-3">
                    <span className="text-secondary-400 text-sm">Expiry:</span>
                    <span className={`ml-2 text-sm font-medium ${
                      claim.isExpired ? 'text-error-500' : 'text-warning-500'
                    }`}>
                      {formatDate(claim.expiryTs)} ({formatTimeRemaining(claim.timeRemaining)})
                    </span>
                  </div>
                )}

                {claim.data && claim.data !== '' && (
                  <div className="mt-2">
                    <span className="text-secondary-400 text-sm">Data:</span>
                    <span className="text-white ml-2 text-sm font-mono">
                      {claim.data}
                    </span>
                  </div>
                )}
              </div>

              {/* Bridge Contract Address */}
              <div className="ml-4 text-right">
                <div className="text-xs text-secondary-400 mb-1">Bridge Contract</div>
                <div className="text-xs font-mono text-white">
                  {formatAddress(claim.bridgeAddress)}
                </div>
              </div>
            </div>
          </motion.div>
        ))}
      </AnimatePresence>
    </div>
  );
};

export default ClaimsList;
